// admin/src/services/authService.js
import axios from 'axios';
import api from './axiosClient';

class AuthService {
    /**
     * Gọi API xử lý đăng nhập dành riêng cho Quản trị viên
     * @param {string} email 
     * @param {string} password 
     * @returns {Promise<Object>} Trả về response chứa token và thông tin admin
     */
    async loginAdminApi(email, password) {
        // Auth dùng axios trực tiếp vì chưa có token lúc login
        const response = await axios.post(
            `${api.defaults.baseURL}/admin/login`,
            { email, password }
        );
        return response.data;
    }

    /**
     * Hàm hỗ trợ đăng xuất sạch sẽ khỏi hệ thống
     */
    logout() {
        localStorage.removeItem('token');
        localStorage.removeItem('user');
    }
}

export default new AuthService();
